'use client';

import { useRef } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useGSAP } from '@gsap/react';

gsap.registerPlugin(ScrollTrigger, useGSAP);

const aboutLines = [
  'Building immersive digital worlds for bold brands.',
  'We blend motion, storytelling, and high-end interfaces.',
  'Designed for future-ready products in Web3 culture.',
];

const contactLinks = ['X / TWITTER', 'INSTAGRAM', 'DISCORD', 'BEHANCE'];

type OverlayUIProps = {
  scrollProxyRef: React.RefObject<HTMLDivElement | null>;
};

export default function OverlayUI({ scrollProxyRef }: OverlayUIProps) {
  const rootRef = useRef<HTMLDivElement>(null);
  const heroRef = useRef<HTMLDivElement>(null);
  const aboutRef = useRef<HTMLDivElement>(null);
  const contactRef = useRef<HTMLDivElement>(null);
  const aboutLineRefs = useRef<(HTMLParagraphElement | null)[]>([]);
  const contactLinkRefs = useRef<(HTMLAnchorElement | null)[]>([]);

  useGSAP(
    () => {
      if (!scrollProxyRef.current) return;

      gsap.set([aboutRef.current, contactRef.current], { autoAlpha: 0 });
      gsap.set(aboutLineRefs.current, { y: 50, autoAlpha: 0 });
      gsap.set(contactLinkRefs.current, { y: 40, autoAlpha: 0 });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: scrollProxyRef.current,
          start: 'top top',
          end: 'bottom bottom',
          scrub: 1,
        },
      });

      tl.to(heroRef.current, {
        scale: 1.2,
        autoAlpha: 0,
        ease: 'none',
        duration: 1.2,
      })
        .to(
          aboutRef.current,
          {
            autoAlpha: 1,
            duration: 0.2,
          },
          '>-0.2',
        )
        .to(
          aboutLineRefs.current,
          {
            y: 0,
            autoAlpha: 1,
            stagger: 0.1,
            ease: 'power2.out',
            duration: 0.8,
          },
          '<',
        )
        .to(aboutRef.current, {
          x: -120,
          y: 40,
          autoAlpha: 0,
          ease: 'power2.inOut',
          duration: 0.8,
        })
        .to(
          contactRef.current,
          {
            autoAlpha: 1,
            duration: 0.2,
          },
          '<0.2',
        )
        .to(
          contactLinkRefs.current,
          {
            y: 0,
            autoAlpha: 1,
            stagger: 0.08,
            ease: 'power2.out',
            duration: 0.8,
          },
          '<',
        );
    },
    { scope: rootRef },
  );

  return (
    <div ref={rootRef} className="fixed inset-0 z-20 h-screen w-screen overflow-hidden bg-zinc-950 text-white">
      <header className="absolute top-0 z-50 w-full px-6 py-5 md:px-10">
        <nav className="flex items-center justify-between">
          <a href="#" className="pointer-events-auto text-lg font-black uppercase tracking-tight">
            HAPE CLONING
          </a>
          <ul className="flex items-center gap-6 text-sm font-semibold uppercase tracking-wide">
            {['About', 'Works', 'Contact'].map((item) => (
              <li key={item}>
                <a href="#" className="pointer-events-auto text-white/80 transition hover:text-white">
                  {item}
                </a>
              </li>
            ))}
          </ul>
        </nav>
      </header>

      <section className="absolute inset-0 z-0 flex items-center justify-center">
        <div
          ref={heroRef}
          className="pointer-events-none select-none text-center text-[15vw] font-black uppercase leading-[0.88] tracking-tighter text-white/20 [text-shadow:0_0_24px_rgba(255,255,255,0.1)]"
        >
          HAPE
          <br />
          STUDIO
        </div>
      </section>

      <section className="pointer-events-none absolute inset-0 z-10 flex items-center justify-center">
        <div className="h-[52vmin] w-[52vmin] rounded-full border border-dashed border-white/20 bg-transparent" />
      </section>

      <div className="pointer-events-none absolute inset-0 z-20">
        <section ref={aboutRef} className="absolute bottom-10 left-6 max-w-[34rem] md:bottom-14 md:left-10">
          <h2 className="mb-4 text-4xl font-black uppercase tracking-tighter md:text-5xl">About</h2>
          <div className="space-y-2 text-sm font-medium uppercase tracking-wide text-white/90 md:text-base">
            {aboutLines.map((line, index) => (
              <p
                key={line}
                ref={(el) => {
                  aboutLineRefs.current[index] = el;
                }}
              >
                {line}
              </p>
            ))}
          </div>
        </section>

        <section ref={contactRef} className="absolute right-6 top-24 text-right md:right-10 md:top-28">
          <h2 className="mb-5 text-3xl font-black uppercase tracking-tighter md:text-5xl">Contact</h2>
          <div className="flex flex-col gap-2 md:gap-3">
            {contactLinks.map((label, index) => (
              <a
                key={label}
                href="#"
                ref={(el) => {
                  contactLinkRefs.current[index] = el;
                }}
                className="pointer-events-auto text-2xl font-black uppercase tracking-tighter text-white/90 transition hover:text-white md:text-4xl"
              >
                {label}
              </a>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
}
